import socket
import struct
import json
import machine
import time

# CoAP Constants
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Message Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Method Codes
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes
CREATED = (2, 1)
DELETED = (2, 2)
VALID = (2, 3)
CHANGED = (2, 4)
CONTENT = (2, 5)
BAD_REQUEST = (4, 0)
NOT_FOUND = (4, 4)
METHOD_NOT_ALLOWED = (4, 5)
INTERNAL_ERROR = (5, 0)

# Content Format
CONTENT_FORMAT_TEXT = 0
CONTENT_FORMAT_JSON = 50


class CoapOption:
    def __init__(self, number, value=b''):
        self.number = number
        self.value = value


class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.msg_type = CON
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @property
    def uri_path(self):
        """Extract URI path from options (option number 11)."""
        parts = []
        for opt in self.options:
            if opt.number == 11:
                parts.append(opt.value.decode('utf-8'))
        return '/' + '/'.join(parts) if parts else '/'

    def set_response_code(self, code_tuple):
        self.code_class = code_tuple[0]
        self.code_detail = code_tuple[1]


def parse_coap_message(data):
    """Parse raw bytes into a CoapMessage."""
    if len(data) < 4:
        return None

    msg = CoapMessage()

    # Parse header (4 bytes)
    header = struct.unpack('!BBH', data[0:4])
    msg.version = (header[0] >> 6) & 0x03
    msg.msg_type = (header[0] >> 4) & 0x03
    token_length = header[0] & 0x0F
    msg.code_class = (header[1] >> 5) & 0x07
    msg.code_detail = header[1] & 0x1F
    msg.message_id = header[2]

    offset = 4

    # Parse token
    if token_length > 0 and offset + token_length <= len(data):
        msg.token = data[offset:offset + token_length]
        offset += token_length

    # Parse options
    prev_option_number = 0
    while offset < len(data):
        if data[offset] == 0xFF:
            # Payload marker
            offset += 1
            break

        option_delta = (data[offset] >> 4) & 0x0F
        option_length = data[offset] & 0x0F
        offset += 1

        # Extended delta
        if option_delta == 13:
            option_delta = data[offset] + 13
            offset += 1
        elif option_delta == 14:
            option_delta = struct.unpack('!H', data[offset:offset + 2])[0] + 269
            offset += 2

        # Extended length
        if option_length == 13:
            option_length = data[offset] + 13
            offset += 1
        elif option_length == 14:
            option_length = struct.unpack('!H', data[offset:offset + 2])[0] + 269
            offset += 2

        option_number = prev_option_number + option_delta
        option_value = data[offset:offset + option_length]
        offset += option_length

        msg.options.append(CoapOption(option_number, option_value))
        prev_option_number = option_number

    # Parse payload
    if offset < len(data):
        msg.payload = data[offset:]

    return msg


def build_coap_message(msg):
    """Serialize a CoapMessage into raw bytes."""
    token_length = len(msg.token)
    first_byte = ((msg.version & 0x03) << 6) | ((msg.msg_type & 0x03) << 4) | (token_length & 0x0F)
    code_byte = ((msg.code_class & 0x07) << 5) | (msg.code_detail & 0x1F)

    result = struct.pack('!BBH', first_byte, code_byte, msg.message_id)

    # Token
    if token_length > 0:
        result += msg.token

    # Options (sorted by number)
    sorted_options = sorted(msg.options, key=lambda o: o.number)
    prev_number = 0
    for opt in sorted_options:
        delta = opt.number - prev_number
        length = len(opt.value)

        # Encode delta
        if delta < 13:
            delta_nibble = delta
            delta_ext = b''
        elif delta < 269:
            delta_nibble = 13
            delta_ext = struct.pack('!B', delta - 13)
        else:
            delta_nibble = 14
            delta_ext = struct.pack('!H', delta - 269)

        # Encode length
        if length < 13:
            length_nibble = length
            length_ext = b''
        elif length < 269:
            length_nibble = 13
            length_ext = struct.pack('!B', length - 13)
        else:
            length_nibble = 14
            length_ext = struct.pack('!H', length - 269)

        result += struct.pack('!B', (delta_nibble << 4) | length_nibble)
        result += delta_ext
        result += length_ext
        result += opt.value

        prev_number = opt.number

    # Payload
    if msg.payload:
        result += b'\xFF'
        result += msg.payload

    return result


class DeviceState:
    """Holds the current state of all device resources."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._adc = None
        self._temp_pin = None

        # Try to initialize ADC for temperature reading
        try:
            self._adc = machine.ADC(0)
        except Exception:
            pass

    def read_temperature(self):
        """Read temperature from sensor. Returns dict with temp data."""
        if self._adc:
            try:
                raw = self._adc.read()
                # Convert ADC reading to temperature (example: LM35 or similar)
                # Adjust formula based on your actual sensor
                voltage = raw * 3.3 / 4095
                temp_c = voltage * 100.0
                return {
                    'temperature': round(temp_c, 2),
                    'unit': 'celsius',
                    'raw_adc': raw,
                    'timestamp': time.time()
                }
            except Exception:
                pass

        # Simulated temperature for testing/development
        import urandom
        simulated = 20.0 + (urandom.getrandbits(8) % 150) / 10.0
        return {
            'temperature': round(simulated, 2),
            'unit': 'celsius',
            'simulated': True,
            'timestamp': time.time()
        }

    def get_light_state(self):
        """Return current light/actuator state."""
        return {
            'on': self.light_state,
            'brightness': self.light_brightness,
            'timestamp': time.time()
        }

    def set_light_state(self, payload):
        """Set light state from JSON payload. Returns success boolean and state."""
        try:
            data = json.loads(payload)
            if 'on' in data:
                self.light_state = bool(data['on'])
            if 'brightness' in data:
                self.light_brightness = max(0, min(100, int(data['brightness'])))

            # Drive actual GPIO if available
            self._apply_light_output()

            return True, self.get_light_state()
        except (ValueError, KeyError) as e:
            return False, {'error': str(e)}

    def _apply_light_output(self):
        """Apply light state to hardware GPIO/PWM."""
        try:
            # Example: GPIO2 for on/off, PWM for brightness
            pin = machine.Pin(2, machine.Pin.OUT)
            if self.light_state:
                if self.light_brightness > 0:
                    pwm = machine.PWM(pin)
                    pwm.freq(1000)
                    duty = int(self.light_brightness * 1023 / 100)
                    pwm.duty(duty)
                else:
                    pin.value(1)
            else:
                try:
                    machine.PWM(pin).deinit()
                except Exception:
                    pass
                pin.value(0)
        except Exception:
            # Hardware not available (simulation mode)
            pass


class CoapResource:
    """Represents a single CoAP resource with handlers."""

    def __init__(self, path, get_handler=None, put_handler=None,
                 content_format=CONTENT_FORMAT_JSON):
        self.path = path
        self.get_handler = get_handler
        self.put_handler = put_handler
        self.content_format = content_format


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.resources = {}
        self.sock = None
        self.running = False
        self._msg_id_counter = 0

    def add_resource(self, resource):
        """Register a CoapResource."""
        self.resources[resource.path] = resource
        print("[CoAP] Registered resource: {}".format(resource.path))

    def _next_msg_id(self):
        self._msg_id_counter = (self._msg_id_counter + 1) & 0xFFFF
        return self._msg_id_counter

    def _build_response(self, request, code, payload=b'', content_format=None):
        """Build a CoAP response message."""
        resp = CoapMessage()
        resp.version = COAP_VERSION

        if request.msg_type == CON:
            resp.msg_type = ACK
        else:
            resp.msg_type = NON

        resp.code_class = code[0]
        resp.code_detail = code[1]
        resp.message_id = request.message_id
        resp.token = request.token

        # Add content-format option if payload present
        if payload and content_format is not None:
            resp.options.append(CoapOption(12, struct.pack('!B', content_format)))

        if isinstance(payload, str):
            payload = payload.encode('utf-8')
        resp.payload = payload

        return resp

    def _handle_request(self, data, addr):
        """Process incoming CoAP request and return response bytes."""
        msg = parse_coap_message(data)
        if msg is None:
            return None

        uri = msg.uri_path
        method_code = msg.code_detail

        print("[CoAP] {} {} from {}".format(
            {GET: 'GET', PUT: 'PUT', POST: 'POST', DELETE: 'DELETE'}.get(method_code, '?'),
            uri, addr
        ))

        # Well-known core resource discovery
        if uri == '/.well-known/core' and method_code == GET:
            links = []
            for path, res in self.resources.items():
                link = '<{}>'.format(path)
                attrs = []
                if res.content_format == CONTENT_FORMAT_JSON:
                    attrs.append('ct=50')
                if res.get_handler:
                    attrs.append('rt="observe"')
                if attrs:
                    link += ';' + ';'.join(attrs)
                links.append(link)
            payload = ','.join(links)
            resp = self._build_response(msg, CONTENT, payload,
                                        content_format=40)  # application/link-format
            return build_coap_message(resp)

        # Look up resource
        resource = self.resources.get(uri)
        if resource is None:
            resp = self._build_response(msg, NOT_FOUND,
                                        json.dumps({'error': 'Resource not found'}),
                                        CONTENT_FORMAT_JSON)
            return build_coap_message(resp)

        # Handle GET
        if method_code == GET:
            if resource.get_handler:
                try:
                    result = resource.get_handler()
                    payload = json.dumps(result)
                    resp = self._build_response(msg, CONTENT, payload,
                                                resource.content_format)
                except Exception as e:
                    resp = self._build_response(msg, INTERNAL_ERROR,
                                                json.dumps({'error': str(e)}),
                                                CONTENT_FORMAT_JSON)
            else:
                resp = self._build_response(msg, METHOD_NOT_ALLOWED,
                                            json.dumps({'error': 'GET not supported'}),
                                            CONTENT_FORMAT_JSON)
            return build_coap_message(resp)

        # Handle PUT
        if method_code == PUT:
            if resource.put_handler:
                try:
                    result = resource.put_handler(msg.payload)
                    payload = json.dumps(result)
                    resp = self._build_response(msg, CHANGED, payload,
                                                resource.content_format)
                except Exception as e:
                    resp = self._build_response(msg, INTERNAL_ERROR,
                                                json.dumps({'error': str(e)}),
                                                CONTENT_FORMAT_JSON)
            else:
                resp = self._build_response(msg, METHOD_NOT_ALLOWED,
                                            json.dumps({'error': 'PUT not supported'}),
                                            CONTENT_FORMAT_JSON)
            return build_coap_message(resp)

        # Unsupported method
        resp = self._build_response(msg, METHOD_NOT_ALLOWED,
                                    json.dumps({'error': 'Method not allowed'}),
                                    CONTENT_FORMAT_JSON)
        return build_coap_message(resp)

    def start(self):
        """Start the CoAP server (blocking)."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))
        # Set timeout so we can check self.running periodically
        self.sock.settimeout(1.0)
        self.running = True

        print("[CoAP] Server listening on {}:{}".format(self.host, self.port))
        print("[CoAP] Resources:")
        for path in self.resources:
            res = self.resources[path]
            methods = []
            if res.get_handler:
                methods.append('GET')
            if res.put_handler:
                methods.append('PUT')
            print("  {} [{}]".format(path, ', '.join(methods)))

        while self.running:
            try:
                data, addr = self.sock.recvfrom(1024)
                response = self._handle_request(data, addr)
                if response:
                    self.sock.sendto(response, addr)
            except OSError:
                # Timeout - continue loop
                continue
            except KeyboardInterrupt:
                print("\n[CoAP] Shutting down...")
                self.running = False
            except Exception as e:
                print("[CoAP] Error: {}".format(e))

        self.sock.close()
        print("[CoAP] Server stopped.")

    def stop(self):
        """Signal the server to stop."""
        self.running = False


def setup_wifi(ssid, password, timeout=15):
    """Connect to WiFi network (ESP32/ESP8266)."""
    try:
        import network
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)

        if wlan.isconnected():
            print("[WiFi] Already connected: {}".format(wlan.ifconfig()[0]))
            return True

        print("[WiFi] Connecting to '{}'...".format(ssid))
        wlan.connect(ssid, password)

        start = time.time()
        while not wlan.isconnected():
            if time.time() - start > timeout:
                print("[WiFi] Connection timeout!")
                return False
            time.sleep(0.5)

        ip = wlan.ifconfig()[0]
        print("[WiFi] Connected! IP: {}".format(ip))
        return True
    except ImportError:
        print("[WiFi] network module not available (not running on ESP?)")
        return True  # Allow running on desktop for testing


def main():
    # --- Configuration ---
    WIFI_SSID = "YOUR_WIFI_SSID"
    WIFI_PASS = "YOUR_WIFI_PASSWORD"
    COAP_BIND_PORT = 5683

    # Connect to WiFi
    setup_wifi(WIFI_SSID, WIFI_PASS)

    # Initialize device state
    device = DeviceState()

    # --- Define resource handlers ---

    def handle_temp_get():
        """GET /sensors/temp - Read temperature sensor."""
        return device.read_temperature()

    def handle_light_get():
        """GET /actuators/light - Get current light state."""
        return device.get_light_state()

    def handle_light_put(payload):
        """PUT /actuators/light - Set light state.
        Expects JSON: {"on": true/false, "brightness": 0-100}
        """
        success, result = device.set_light_state(payload)
        if not success:
            raise ValueError(result.get('error', 'Invalid request'))
        return result

    def handle_device_info_get():
        """GET /device/info - Device metadata."""
        try:
            import os
            uname = os.uname()
            platform = uname.sysname
            machine_name = uname.machine
        except Exception:
            platform = 'unknown'
            machine_name = 'unknown'

        mem_free = 0
        try:
            import gc
            gc.collect()
            mem_free = gc.mem_free()
        except Exception:
            pass

        return {
            'device': 'iot-coap-node',
            'platform': platform,
            'machine': machine_name,
            'mem_free': mem_free,
            'uptime': time.time(),
            'coap_port': COAP_BIND_PORT,
            'resources': list(server.resources.keys()) if server else []
        }

    # --- Create and configure server ---
    server = CoapServer(host='0.0.0.0', port=COAP_BIND_PORT)

    # Temperature sensor resource (read-only)
    server.add_resource(CoapResource(
        path='/sensors/temp',
        get_handler=handle_temp_get
    ))

    # Light actuator resource (read/write)
    server.add_resource(CoapResource(
        path='/actuators/light',
        get_handler=handle_light_get,
        put_handler=handle_light_put
    ))

    # Device info resource (read-only)
    server.add_resource(CoapResource(
        path='/device/info',
        get_handler=handle_device_info_get
    ))

    # Start server (blocking)
    try:
        server.start()
    except KeyboardInterrupt:
        server.stop()


if __name__ == '__main__':
    main()